function [rslt] = fFitGausV03(x,y,rat,stp)% Perform fitting to Gaussian distribution%% [] = fFitGausV01(x,cnts,ratio)% x: axis information (x axis)% y: counts for each point (yaxis)% rat: difine threshold to fit, 0.2 will cut below 0.2 x peak% stp: input will be interpolatd into number of stp for fitting%% rslt: structure with the fields%       sig^2,u          - fitted parameters%       CRB_sig2,CRB_u   - Cram?r-Rao Bound for the estimator value%       RMS              - RMS error of the estimation %       type             - 'ML'%       cff              - coefficient for distribution%%%%%%%%%%%%%%%%%%%%%%%%%%%%%% Fit Gaussian, ver.1%% Kei Nakamura% Created on Thursday, February 11th 2010.% Modified on %% ver.1: created% ver.2: fix cff% ver.3: try some crazy for peak%%%%%%%%%%%%%%%%%%%%%%%%%%%%% main body%% roi[wHIn,wLIn,wHOut,wLOut,peak] = fGetFwAnyMaxV01([1:numel(x)],y,rat);    % for roix1 = round(peak-wLOut); x2 = round(peak+wHOut);fitY = y(x1:x2); fitX = x(x1:x2);    % roi for fit% fit1ttlCnt = sum(sum(fitY));hst = fGetHstV01(fitX,fitY);    % to get histogram for fittingrslt1 = fit_ML_normal(hst);yRslt = exp(-(fitX-rslt1.u).^2/rslt1.sig2);cff1 = ttlCnt/sum(sum(yRslt));yRslt1 = cff1*exp(-(fitX-rslt1.u).^2/rslt1.sig2);% figure for fit1figure(10)plot(fitX,fitY,'ro')hold onplot(fitX,yRslt1,'b-')% interpolationstpIntp = (fitX(end)-fitX(1))/(stp-1);intpX = fitX(1):stpIntp:fitX(end);  % interpolated xintpY = interp1(fitX,fitY,intpX);      % interpolated y% extrapolationp1 = polyfit(intpX(1:round(0.1*stp)),intpY(1:round(0.1*stp)),1);xStrt = -p1(2)/p1(1);extpX1 = xStrt:stpIntp:(intpX(1)-stpIntp);extpY1 = polyval(p1,extpX1);p2 = polyfit(intpX(round(0.9*stp):end),intpY(round(0.9*stp):end),1);xEnd = -p2(2)/p2(1);extpX2 = (intpX(end)+stpIntp):stpIntp:xEnd;extpY2 = polyval(p2,extpX2);intpX = [extpX1,intpX,extpX2];intpY = [extpY1,intpY,extpY2];hst = fGetHstV01(intpX,intpY);    % to get histogram for fittingrslt = fit_ML_normal(hst);ttlCnt = sum(intpY);  % total countsyRslt = exp(-(intpX-rslt.u).^2/rslt.sig2);cff = ttlCnt/sum(sum(yRslt));yRslt = cff*exp(-(intpX-rslt.u).^2/rslt.sig2);plot(intpX,yRslt,'g-')hold off% uHigh = fitX(end) - rslt.u;     % width high side% uHighN = uHigh/sqrt(rslt.sig2);  % width in terms of number of sigma% uLow = rslt.u - fitX(1);         % width low side% uLowN = uLow/sqrt(rslt.sig2);    % width in terms of number of sigma% erfH = 0.5*erf(uHighN/sqrt(2));       % integrated probability for high side% erfL = 0.5*erf(uLowN/sqrt(2));        % for low side% ttlPrb = erfH+erfL;             % total probability in fitted region% fitTtlCnt = ttlCnt/ttlPrb;      % total counts including outside for fitted result% cff = (intpX(2)-intpX(1))*fitTtlCnt/sqrt(2*pi*rslt.sig2);% rslt.cff = cff;
